1	const PROCESSING_FEE = 5;
2	const COMPONENT_PREMIUM = 25;
3	const BLOCK_PREMIUM = 60;
4	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
5	
6	const BLOCK_SIZE = 3;
7	const CURSED_SURCHARGE_RATE = 0.5;
8	const HIGH_ENCHANTMENT_QUOTE_THRESHOLD = 5;
9	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
10	const FIRST_INSURANCE_RATE = 0.1;
11	const LOYALTY_DISCOUNT_RATE = 0.2;
12	const LOYALTY_MIN_YEARS = 2;
13	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
14	
15	const isComponent = (item: any): boolean => COMPONENT_TYPES.has(item.type);
16	
17	const BASE_PREMIUMS: Record<string, number> = {
18	  sword: 100,
19	  amulet: 60,
20	};
21	
22	const basePremium = (item: any): number => {
23	  if (!isComponent(item) && !(item.type in BASE_PREMIUMS)) {
24	    throw new Error(`Unknown item type: ${item.type}`);
25	  }
26	  return BASE_PREMIUMS[item.type] ?? 0;
27	};
28	
29	const itemSurcharges = (item: any): number => {
30	  const base = basePremium(item);
31	  const cursedSurcharge = item.cursed ? base * CURSED_SURCHARGE_RATE : 0;
32	  const enchantmentSurcharge = item.enchantment >= HIGH_ENCHANTMENT_QUOTE_THRESHOLD ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE : 0;
33	  return cursedSurcharge + enchantmentSurcharge;
34	};
35	
36	const totalComponentPremium = (items: any[]): number => {
37	  const components = items.filter(isComponent);
38	  const counts: Record<string, number> = {};
39	  for (const c of components) {
40	    counts[c.type] = (counts[c.type] ?? 0) + 1;
41	  }
42	  let total = 0;
43	  for (const count of Object.values(counts)) {
44	    if (count === BLOCK_SIZE) {
45	      total += BLOCK_PREMIUM;
46	    } else {
47	      total += count * COMPONENT_PREMIUM;
48	    }
49	  }
50	  return total;
51	};
52	
53	const calculateQuotePremium = (items: any[], customer: any, isFollowUp: boolean): number => {
54	  const mainItems = items.filter((i: any) => !isComponent(i));
55	  const mainBaseTotal = mainItems.reduce(
56	    (sum: number, item: any) => sum + basePremium(item),
57	    0,
58	  );
59	  const mainSurchargesTotal = mainItems.reduce(
60	    (sum: number, item: any) => sum + itemSurcharges(item),
61	    0,
62	  );
63	  const compTotal = totalComponentPremium(items);
64	  const policyBase = mainBaseTotal + compTotal;
65	  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
66	  const loyaltyDiscount = customer.yearsWithMHPCO >= LOYALTY_MIN_YEARS ? policyBase * LOYALTY_DISCOUNT_RATE : 0;
67	  const followUpDiscount = isFollowUp ? policyBase * FOLLOW_UP_DISCOUNT_RATE : 0;
68	  return Math.ceil(PROCESSING_FEE + mainBaseTotal + mainSurchargesTotal + compTotal + firstInsurance - loyaltyDiscount - followUpDiscount);
69	};
70	
71	const INSURANCE_VALUES: Record<string, number> = {
72	  sword: 1000,
73	  amulet: 600,
74	  staff: 800,
75	  potion: 400,
76	};
77	
78	const DEDUCTIBLE = 100;
79	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
80	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
81	
82	const insuranceValue = (item: any): number => {
83	  if (isComponent(item)) return 250;
84	  return INSURANCE_VALUES[item.type] ?? 0;
85	};
86	
87	const reimbursementAmount = (item: any, damageAmount: number): number => {
88	  if (item && item.enchantment >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD) {
89	    return damageAmount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE;
90	  }
91	  return damageAmount;
92	};
93	
94	const calculateClaimPayout = (policy: any, incident: any): { payout: number; remainingCap: number } => {
95	  const insuranceSum = policy.items.reduce(
96	    (sum: number, item: any) => sum + insuranceValue(item), 0
97	  );
98	  const cap = insuranceSum * 2;
99	  let totalPayout = 0;
100	  for (const damage of incident.damages) {
101	    const item = policy.items.find((i: any) => i.type === damage.itemType);
102	    const payout = reimbursementAmount(item, damage.amount) - DEDUCTIBLE;
103	    totalPayout += payout;
104	  }
105	  const cappedPayout = Math.min(totalPayout, cap);
106	  return { payout: cappedPayout, remainingCap: cap - cappedPayout };
107	};
108	
109	export const processScenario = (scenario: any): any => {
110	  let quoteCount = 0;
111	  const policies: any[] = [];
112	  const results = scenario.steps.map((step: any, index: number) => {
113	    if (step.op === "claim") {
114	      return calculateClaimPayout(policies[step.policy], step.incident);
115	    }
116	    policies[index] = { items: step.items };
117	    const premium = calculateQuotePremium(step.items, scenario.customer, quoteCount > 0);
118	    quoteCount++;
119	    return { premium };
120	  });
121	  return { results };
122	};
